import{_ as s,c as a,o as t,ae as n}from"./chunks/framework.Cd-3tpCq.js";const m=JSON.parse('{"title":"Étape 1.3 — Les types de composants Canvas","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/component-types.md","filePath":"drupal-canvas/component-types.md"}'),o={name:"drupal-canvas/component-types.md"};function r(l,e,i,p,d,c){return t(),a("div",null,e[0]||(e[0]=[n(`<h1 id="etape-1-3-—-les-types-de-composants-canvas" tabindex="-1">Étape 1.3 — Les types de composants Canvas <a class="header-anchor" href="#etape-1-3-—-les-types-de-composants-canvas" aria-label="Permalink to &quot;Étape 1.3 — Les types de composants Canvas&quot;">​</a></h1><p>Dans <strong>Drupal Canvas</strong>, il existe trois familles de composants. Comprendre leurs rôles respectifs est essentiel avant de commencer à construire.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Créé par</th><th>Modifiable dans l&#39;UI</th><th>Portée</th></tr></thead><tbody><tr><td><strong>Code Components (SDC)</strong></td><td>Le développeur</td><td>Oui (contenu/style)</td><td>Une page</td></tr><tr><td><strong>Pattern Components</strong></td><td>L&#39;éditeur</td><td>Oui</td><td>Toutes les pages</td></tr><tr><td><strong>Global Components</strong></td><td>Le développeur + l&#39;éditeur</td><td>Oui</td><td>Toutes les pages</td></tr></tbody></table><hr><h2 id="_1-code-components-sdc" tabindex="-1">1. Code Components (SDC) <a class="header-anchor" href="#_1-code-components-sdc" aria-label="Permalink to &quot;1. Code Components (SDC)&quot;">​</a></h2><p>Les <strong>Code Components</strong> sont des composants développés en code, selon la norme <strong>Single Directory Components (SDC)</strong> introduite dans Drupal 10.3.</p><h3 id="comment-ils-fonctionnent" tabindex="-1">Comment ils fonctionnent <a class="header-anchor" href="#comment-ils-fonctionnent" aria-label="Permalink to &quot;Comment ils fonctionnent&quot;">​</a></h3><p>Chaque composant est un dossier auto-suffisant dans le thème, contenant :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mon_theme/</span></span>
<span class="line"><span>└── components/</span></span>
<span class="line"><span>    └── hero/</span></span>
<span class="line"><span>        ├── hero.component.yml   ← définition du composant + props</span></span>
<span class="line"><span>        ├── hero.twig            ← template HTML</span></span>
<span class="line"><span>        ├── hero.css             ← styles du composant</span></span>
<span class="line"><span>        └── hero.js              ← comportements JS (optionnel)</span></span></code></pre></div><h3 id="leur-role-dans-canvas" tabindex="-1">Leur rôle dans Canvas <a class="header-anchor" href="#leur-role-dans-canvas" aria-label="Permalink to &quot;Leur rôle dans Canvas&quot;">​</a></h3><p>Une fois développés, ces composants apparaissent <strong>dans le panneau de gauche de l&#39;éditeur Canvas</strong>. L&#39;éditeur peut les glisser-déposer sur la page et remplir leurs champs (props) depuis le panneau de droite.</p><div class="tip custom-block"><p class="custom-block-title">Analogie</p><p>Un Code Component, c&#39;est une <strong>brique LEGO</strong> : c&#39;est le développeur qui la fabrique, et l&#39;éditeur qui l&#39;assemble.</p></div><h3 id="ce-que-vous-allez-creer-dans-ce-cours" tabindex="-1">Ce que vous allez créer dans ce cours <a class="header-anchor" href="#ce-que-vous-allez-creer-dans-ce-cours" aria-label="Permalink to &quot;Ce que vous allez créer dans ce cours&quot;">​</a></h3><p>Nous allons créer ensemble les composants SDC suivants :</p><table tabindex="0"><thead><tr><th>Composant</th><th>Description</th></tr></thead><tbody><tr><td><code>hero</code></td><td>Bannière principale pleine largeur</td></tr><tr><td><code>card</code></td><td>Carte réutilisable (image + titre + texte)</td></tr><tr><td><code>grid</code></td><td>Grille conteneur pour d&#39;autres composants</td></tr><tr><td><code>navigation</code></td><td>Menu de navigation + logo</td></tr></tbody></table><hr><h2 id="_2-pattern-components" tabindex="-1">2. Pattern Components <a class="header-anchor" href="#_2-pattern-components" aria-label="Permalink to &quot;2. Pattern Components&quot;">​</a></h2><p>Les <strong>Pattern Components</strong> (ou simplement &quot;Patterns&quot;) sont des <strong>assemblages de composants SDC sauvegardés depuis l&#39;interface Canvas</strong>.</p><h3 id="comment-ils-se-creent" tabindex="-1">Comment ils se créent <a class="header-anchor" href="#comment-ils-se-creent" aria-label="Permalink to &quot;Comment ils se créent&quot;">​</a></h3><ol><li>Vous construisez une mise en page dans Canvas (ex : une grille de 3 cartes avec un titre au-dessus).</li><li>Vous sauvegardez cet ensemble comme <strong>Pattern réutilisable</strong>.</li><li>Le Pattern apparaît alors dans la bibliothèque, disponible pour toutes les pages du site.</li></ol><h3 id="leur-role" tabindex="-1">Leur rôle <a class="header-anchor" href="#leur-role" aria-label="Permalink to &quot;Leur rôle&quot;">​</a></h3><p>Les Patterns permettent à l&#39;<strong>éditeur de contenu</strong> de réutiliser des mises en page sans avoir à tout reconstruire à chaque fois.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pattern &quot;Services&quot; =</span></span>
<span class="line"><span>  Titre de section</span></span>
<span class="line"><span>  + Grille 3 colonnes</span></span>
<span class="line"><span>      + Carte (icône + titre + texte)</span></span>
<span class="line"><span>      + Carte (icône + titre + texte)</span></span>
<span class="line"><span>      + Carte (icône + titre + texte)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Les Patterns sont stockés en base de données (configuration Drupal), pas dans les fichiers du thème. Ils sont donc exportables via <code>drush config:export</code>.</p></div><hr><h2 id="_3-global-components" tabindex="-1">3. Global Components <a class="header-anchor" href="#_3-global-components" aria-label="Permalink to &quot;3. Global Components&quot;">​</a></h2><p>Les <strong>Global Components</strong> sont des zones partagées sur <strong>toutes les pages du site</strong> : typiquement le <strong>Header</strong> et le <strong>Footer</strong>.</p><h3 id="comment-ils-fonctionnent-1" tabindex="-1">Comment ils fonctionnent <a class="header-anchor" href="#comment-ils-fonctionnent-1" aria-label="Permalink to &quot;Comment ils fonctionnent&quot;">​</a></h3><p>Canvas met à disposition des <strong>Régions globales</strong> (Global Regions), indépendantes des pages individuelles. Ce que vous placez dans une Global Region apparaît automatiquement sur chaque page.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chemin : Canvas → Global Components → Header</span></span>
<span class="line"><span>                                    → Footer</span></span></code></pre></div><h3 id="leur-particularite" tabindex="-1">Leur particularité <a class="header-anchor" href="#leur-particularite" aria-label="Permalink to &quot;Leur particularité&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Détail</th></tr></thead><tbody><tr><td><strong>Portée</strong></td><td>Toutes les Canvas Pages du site</td></tr><tr><td><strong>Édition</strong></td><td>Depuis l&#39;interface Canvas dédiée aux Global Components</td></tr><tr><td><strong>Contenu</strong></td><td>Logo, navigation, liens footer, copyright…</td></tr><tr><td><strong>Modification</strong></td><td>Changer le Header ici le met à jour sur toutes les pages</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">⚠️ Attention</p><p>Les Global Components ne s&#39;appliquent qu&#39;aux <strong>Canvas Pages</strong>. Les pages Drupal classiques (nœuds) utilisent les régions du thème définies dans le <code>.info.yml</code>.</p></div><hr><h2 id="recapitulatif-qui-fait-quoi" tabindex="-1">Récapitulatif : qui fait quoi ? <a class="header-anchor" href="#recapitulatif-qui-fait-quoi" aria-label="Permalink to &quot;Récapitulatif : qui fait quoi ?&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DÉVELOPPEUR                     ÉDITEUR</span></span>
<span class="line"><span>─────────────────────           ─────────────────────────────────</span></span>
<span class="line"><span>Crée les SDC                →   Assemble les SDC sur les pages</span></span>
<span class="line"><span>(code, Twig, CSS)               (drag &amp; drop dans Canvas)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                            →   Crée des Patterns</span></span>
<span class="line"><span>                                (sauvegarde des assemblages)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Crée la structure               Remplit le contenu</span></span>
<span class="line"><span>du Header/Footer SDC        →   dans les Global Components</span></span></code></pre></div><p>Dans la suite de ce cours, vous allez d&#39;abord créer les composants SDC (Module 3), puis les assembler pour construire le Header/Footer (Module 4), les pages (Module 5) et les Patterns (Module 6).</p>`,38)]))}const h=s(o,[["render",r]]);export{m as __pageData,h as default};
